                                null,							//pLeft
                                null,							//pExistTF - 중복체크여부	("F")
                                null,							//pAllSearchTF - 전체검색허용여부	("F")
                                "청구 거래처,거래처코드,거래처명",	//pWtitleSearch - POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                null,							//Data건수가 0건일때 Window를 뛰우지 않음 리턴:"N/A"
                                null
                                ); 
            break;

        default:
            break;
    }
}
