/**
 * @method 
 * @name f_multiChoice  
 * @description N건선택 (shift 나 ctrl로 그리드 로우선택후 체크박스 표시)
 */
scwin.f_multiChoice = function () {

    const focusIdxs = gr_certidetail.getAllFocusedRowIndex();

    let choiceVal = 'F'
    if (scwin.chkFlag) choiceVal = 'T';

    scwin.chkFlag = !scwin.chkFlag;

    focusIdxs.forEach((rowIdx) => {
        ds_certidetail.setCellData(rowIdx, 'choice', choiceVal);
    });

};



/**
 * @method 
 * @name gridFormat 
 * @description 그리드 customFormatter
 */
scwin.gridFormat = function (data, formattedData, rowIndex, colIndex) {

    let colID = this.getColumnID(colIndex);
    let rowData = this._dataList.getRowJSON(rowIndex);

    switch (colID) {
        case 'vsslCd': return data + '/' + rowData['portcnt'];
        case 'transDst': return rowData['transDstOn'] + '-' + rowData['transDstOff'];
        case 'exchSellAmt':
            nAdptExchRt = $c.num.parseFloat(rowData['adptExchRt']); // 환율
            nSpplyAmtFcrc = $c.num.parseFloat(rowData['spplyAmtFcrc'], 0); // 외화
            var num = $c.num.round(nAdptExchRt * nSpplyAmtFcrc, 2);
            if(num == 0){
                num = "-0.00";
            }else{
                num = $c.num.round(nAdptExchRt * nSpplyAmtFcrc, 2).toLocaleString()
            }
            return num;
        case 'odrNo': return rowData['odrNo'] + '-' + rowData['sellSeq'];
        default: return formattedData;
    };
};


