        } else if(scwin.pgmId == "fs_202_05_05b.jsp") {
            options.sheetName = "기간매출 CERTI 생성";			
            options.fileName = "기간매출 CERTI 생성.xls";								
        }				

        $c.data.downloadGridViewExcel(gr_certidetail, options, infoArr);
